/* ══════════════════════════════════════════
   TYPEWRITER WORD
══════════════════════════════════════════ */
function TypewriterWord() {
  const words = ["systems", "strategy", "value", "outcomes", "intelligence"];
  const [idx, setIdx] = useState(0);
  const [displayed, setDisplayed] = useState("");
  const [deleting, setDeleting] = useState(false);
  const [paused, setPaused] = useState(false);

  useEffect(() => {
    const target = words[idx];
    if (paused) {
      const t = setTimeout(() => { setPaused(false); setDeleting(true); }, 1800);
      return () => clearTimeout(t);
    }
    if (!deleting) {
      if (displayed.length < target.length) {
        const t = setTimeout(() => setDisplayed(target.slice(0, displayed.length + 1)), 65);
        return () => clearTimeout(t);
      } else {
        setPaused(true);
      }
    } else {
      if (displayed.length > 0) {
        const t = setTimeout(() => setDisplayed(displayed.slice(0, -1)), 38);
        return () => clearTimeout(t);
      } else {
        setDeleting(false);
        setIdx((idx + 1) % words.length);
      }
    }
  }, [displayed, deleting, paused, idx]);

  return (
    <span style={{ color: "#7C3AED", fontWeight: 800 }}>
      {displayed}
      <span style={{
        display: "inline-block", width: "2px", height: "0.85em",
        background: "#7C3AED", marginLeft: "2px", verticalAlign: "text-bottom",
        animation: "blink 1s step-end infinite"
      }} />
    </span>
  );
}

