/* ══════════════════════════════════════════
   NODE DIAGRAM — animated SVG paths
══════════════════════════════════════════ */
function NodeDiagram() {
  const ref  = useRef(null);
  const show = useInView(ref, { once: true, margin: "-100px" });

  const NW = 160, NH = 72, NY = 40, GAP = 32, RX = 8;
  const nodes = [
    { icon: Database, label: "Data Layer",     sub: "Raw signals",      col: "#7C3AED" },
    { icon: Bot,      label: "AI Agents",      sub: "Reasoning + orchestration", col: "#7C3AED" },
    { icon: GitBranch,label: "Decision Layer", sub: "Routing & logic",  col: "#7C3AED" },
    { icon: Zap,      label: "Action",         sub: "Autonomous execution", col: "#7C3AED" },
  ];
  const nodeXs = nodes.map((_, i) => i * (NW + GAP));
  const SVG_W  = nodeXs[3] + NW + 8;
  const SVG_H  = NY + NH + 80;
  const CY     = NY + NH / 2;

  return (
    <div ref={ref} className="w-full overflow-x-auto">
      <svg viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        style={{ minWidth: 540, width: "100%", maxWidth: 900, display: "block", margin: "0 auto" }}>
        <defs>
          <marker id="arr" markerWidth="8" markerHeight="6" refX="7" refY="3" orient="auto">
            <polygon points="0 0,8 3,0 6" fill={V} opacity=".65" />
          </marker>
          <filter id="vglow">
            <feGaussianBlur stdDeviation="3" result="blur" />
            <feMerge><feMergeNode in="blur" /><feMergeNode in="SourceGraphic" /></feMerge>
          </filter>
        </defs>

        {/* Connector lines */}
        {nodes.slice(0, -1).map((_, i) => {
          const x1 = nodeXs[i] + NW, x2 = nodeXs[i + 1];
          return (
            <g key={i}>
              {/* dashed bg line */}
              <line x1={x1} y1={CY} x2={x2} y2={CY}
                stroke="rgba(124,58,237,.18)" strokeWidth="1" strokeDasharray="4 3" />
              {/* animated solid line */}
              <motion.line x1={x1} y1={CY} x2={x2} y2={CY}
                stroke={V} strokeWidth="1.5" markerEnd="url(#arr)"
                filter="url(#vglow)"
                initial={{ opacity: 0, pathLength: 0 }}
                animate={show ? { opacity: 0.6, pathLength: 1 } : {}}
                transition={{ duration: 0.7, delay: 0.5 + i * 0.22, ease: EASE }} />
            </g>
          );
        })}

        {/* Nodes */}
        {nodes.map(({ icon: Icon, label, sub }, i) => {
          const x = nodeXs[i];
          return (
            <motion.g key={i}
              initial={{ opacity: 0, y: 10 }}
              animate={show ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.6, delay: 0.18 + i * 0.14, ease: EASE }}>

              {/* Card */}
              <rect x={x} y={NY} width={NW} height={NH} rx={RX}
                fill="#0d0d10" stroke="rgba(255,255,255,.08)" strokeWidth="1" />

              {/* Violet top bar */}
              <motion.rect x={x + 1} y={NY + 1} width={NW - 2} height={2} rx={1}
                fill={V}
                initial={{ opacity: 0 }} animate={show ? { opacity: 0.7 } : {}}
                transition={{ duration: 0.4, delay: 0.4 + i * 0.14 }} />

              {/* Icon circle */}
              <circle cx={x + 22} cy={CY} r={13}
                fill="rgba(124,58,237,.1)" stroke="rgba(124,58,237,.22)" strokeWidth="1" />

              <foreignObject x={x + 15} y={CY - 7} width={14} height={14}>
                <div style={{ display: "flex", alignItems: "center", justifyContent: "center",
                  width: 14, height: 14, color: "#a78bfa" }}>
                  <Icon size={12} strokeWidth={1.6} />
                </div>
              </foreignObject>

              {/* Label */}
              <text x={x + 40} y={CY - 5}
                fill="rgba(255,255,255,.82)" fontSize="11.5" fontWeight="600"
                style={{ fontFamily: "'DM Sans',sans-serif" }}>{label}</text>

              {/* Sub */}
              <text x={x + 40} y={CY + 10}
                fill="rgba(255,255,255,.25)" fontSize="10"
                style={{ fontFamily: "'JetBrains Mono',monospace" }}>{sub}</text>

              {/* Step */}
              <text x={x + NW - 10} y={NY + 14}
                fill="rgba(255,255,255,.1)" fontSize="10" textAnchor="end"
                style={{ fontFamily: "'JetBrains Mono',monospace" }}>
                {String(i + 1).padStart(2, "0")}
              </text>

              {/* Bottom label */}
              <motion.text x={x + NW / 2} y={NY + NH + 52}
                fill="rgba(255,255,255,.18)" fontSize="10" textAnchor="middle"
                style={{ fontFamily: "'JetBrains Mono',monospace" }}
                initial={{ opacity: 0 }} animate={show ? { opacity: 1 } : {}}
                transition={{ duration: 0.4, delay: 0.8 + i * 0.1 }}>
                {["Inputs", "Intelligence", "Routing", "Output"][i]}
              </motion.text>
            </motion.g>
          );
        })}
      </svg>
    </div>
  );
}

